            return (obj.__assign(_bb.getInt(_bb.position()) + _bb.position(), _bb))
        }
        fun createErrorDetails(builder: FlatBufferBuilder, categoryOffset: Int, artifactKindOffset: Int, foundVersion: UInt, supportedVersion: UInt, messageOffset: Int, guidanceOffset: Int) : Int {
            builder.startTable(6)
            addGuidance(builder, guidanceOffset)
            addMessage(builder, messageOffset)
            addSupportedVersion(builder, supportedVersion)
            addFoundVersion(builder, foundVersion)
            addArtifactKind(builder, artifactKindOffset)
            addCategory(builder, categoryOffset)
            return endErrorDetails(builder)
        }
        fun startErrorDetails(builder: FlatBufferBuilder) = builder.startTable(6)
        fun addCategory(builder: FlatBufferBuilder, category: Int) = builder.addOffset(0, category, 0)
        fun addArtifactKind(builder: FlatBufferBuilder, artifactKind: Int) = builder.addOffset(1, artifactKind, 0)
        fun addFoundVersion(builder: FlatBufferBuilder, foundVersion: UInt) = builder.addInt(2, foundVersion.toInt(), 0)
        fun addSupportedVersion(builder: FlatBufferBuilder, supportedVersion: UInt) = builder.addInt(3, supportedVersion.toInt(), 0)
        fun addMessage(builder: FlatBufferBuilder, message: Int) = builder.addOffset(4, message, 0)
        fun addGuidance(builder: FlatBufferBuilder, guidance: Int) = builder.addOffset(5, guidance, 0)
        fun endErrorDetails(builder: FlatBufferBuilder) : Int {
            val o = builder.endTable()
            return o
        }
    }
}
